func cacheBackendTitle(pc *PageContext, data CacheStatsViewData) string {
	title := pc.T("cache.memory_cache")
	if data.IsRedis {
		title = pc.T("cache.redis_cache")
	}
	if data.IsFallback {
		title += " (" + pc.T("cache.fallback") + ")"
	}
	return title
}

func cacheStatusText(pc *PageContext, data CacheStatsViewData) string {
	if data.HealthError != "" {
		return pc.T("cache.unhealthy") + ": " + data.HealthError
	}
	return pc.T("cache.healthy")
}

func cacheDetail(data CacheStatsViewData) string {
	if data.IsRedis && data.RedisURL != "" {
		return data.RedisURL
	}
	return ""
}

// cacheKindName returns the translated name for a cache kind.
func cacheKindName(pc *PageContext, c CacheItemView) string {
	switch c.Kind {
	case "config":
		return pc.T("cache.name_config")
	case "sitemap":
		return pc.T("cache.name_sitemap")
	case "menu":
		return pc.T("cache.name_menus")
	case "language":
		return pc.T("cache.name_languages")
	case "translation":
		return pc.T("cache.name_translations")
	case "page":
		return pc.T("cache.name_pages")
	case "general":
		return pc.T("cache.name_general")
	default:
		return c.Name
	}
}

